solutions.python:
class Solution:
  def __init__(self):
    pass

  def solve(self):
    # Define the aggregation pipeline
    pipeline = [
      # Iterate over the orderDetails array using $map
      {'$map': {
        "input": "$orderDetails",
        "as": "detail",
        "in": {
          "$mergeObjects": {
            "product": "$$detail.product",
            "quantity": "$$detail.quantity"
          }
        }
      }
    ];

    # Execute the pipeline on a sample document
    result = db.orders.aggregate(pipeline).toArray();
    print(result);
